            o String woof
        }

        concept Neigh {
            o Meow meow
        }

        concept Moo {
            o Neigh neigh
        }

        concept Baa {
            o Moo moo
        }

        asset SampleAsset identified by assetId {
            o String assetId
            --> SampleParticipant owner
            o String value
            o String foo
            o String bar
            o Baa baa
            o String[] noises
            o Meow[] meows
            o DateTime date
        }

