            o String participantId
            o String firstName
            o String lastName
        }

        transaction SampleTransaction {
            o String newValue
        }`);
        queryFile1 = new QueryFile('test.qry', modelManager, `
        query Q1 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleAsset
                    WHERE (value == "Green hat")
        }
        query Q2 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleAsset
        }
        query Q3 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleAsset
                    LIMIT 5
        }
        query Q4 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleAsset
                    SKIP 10
        }
        query Q5 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleAsset
                    LIMIT 5
                    SKIP 10
        }
        query Q6 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleAsset
                    LIMIT _$mylimit
        }
        query Q7 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleAsset
                    SKIP _$myskip
        }
        query Q8 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleAsset
                    WHERE (value == _$foo)
        }
        query Q9 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleAsset
                    FROM DogesSampleAssets
        }
        query Q10 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleParticipant
        }
        query Q11 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleTransaction
        }
        query Q12 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleAsset
                    ORDER BY foo DESC
        }
        query Q13 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleAsset
                    ORDER BY [foo ASC, bar ASC]
        }
        query Q14 {
            description: "Select all drivers aged older than PARAM"
            statement:
                SELECT org.acme.sample.SampleAsset
                    WHERE (baa.moo.neigh.meow.woof == _$animalNoise)
        }
        query Q15 {
            description: "Simple Historian Query"
            statement:
                SELECT org.hyperledger.composer.system.HistorianRecord
                    FROM HistorianRegistry
        }
        query Q16 {
            description: "Simple Historian Query"
            statement:
                SELECT org.acme.sample.SampleAsset
                    WHERE (noises CONTAINS "baa")
        }
        query Q17 {
            description: "Simple Historian Query"
            statement:
                SELECT org.acme.sample.SampleAsset
                    WHERE (noises CONTAINS ["baa","moo"])
        }
        query Q18 {
            description: "Simple Historian Query"
            statement:
                SELECT org.acme.sample.SampleAsset
                    WHERE (meows CONTAINS (woof == "foo"))
        }
        query Q19 {
            description: "Simple Historian Query"
            statement:
                SELECT org.acme.sample.SampleAsset
                    WHERE (meows CONTAINS ((woof == "foo") OR (woof == "noo")))
        }
        query Q20 {
            description: "Select between date range parameters"
            statement:
                SELECT org.acme.sample.SampleAsset
                    WHERE (
                        (date >= _$startTime) AND
                        (date < _$endTime) AND
                        (value == _$value))
        }
        query Q21 {
            description: "Select between date range"
            statement:
                SELECT org.acme.sample.SampleAsset
                    WHERE (
                        (date >= "2018-01-01") AND
                        (date < "2018-02-01") AND
                        (value == "foo"))
        }
        query Q22 {
            description: "Select excluding 2 values"
            statement:
                SELECT org.acme.sample.SampleAsset
                    WHERE (value != 'foo' AND value != 'bar')
        }
        query Q23 {
            description: "Select between date range"
            statement:
                SELECT org.acme.sample.SampleAsset
                    WHERE (
                        date >= "2018-01-01" AND
                        date < "2018-02-01" AND
                        date != "2018-01-15" AND
                        value == "foo")
        }
        `);
        queryFile1.validate();
        queries = {};
        selectsFromQueries = {};
        wheresFromQueries = {};
        orderBysFromQueries = {};
        limitsFromQueries = {};
        skipsFromQueries = {};
        queryFile1.getQueries().forEach((query) => {
            const name = query.getName();
            queries[name] = query;
            selectsFromQueries[name] = query.getSelect();
            wheresFromQueries[name] = query.getSelect().getWhere();
            orderBysFromQueries[name] = query.getSelect().getOrderBy();
            limitsFromQueries[name] = query.getSelect().getLimit();
            skipsFromQueries[name] = query.getSelect().getSkip();
        });
        queryManager = new QueryManager(modelManager);
        queryManager.setQueryFile(queryFile1);
    })

